#include <iostream>
#include <iomanip>
#include <string>

class BankAccount {
protected:
    double balance;
public:
    BankAccount(double b) : balance(b) {}
    void printBalance(std::string label) {
        std::cout << std::fixed << std::setprecision(2);
        std::cout << label << ": " << balance << "\n";
    }
};

class SavingsAccount : public BankAccount {
public:
    SavingsAccount(double b) : BankAccount(b) {}
    void applyInterest(double rate) {
        balance *= (1.0 + rate);
    }
};

int main() {
    double initial, rate;
    std::cin >> initial >> rate;
    SavingsAccount sa(initial);
    sa.printBalance("Initial");
    sa.applyInterest(rate);
    sa.printBalance("After interest");
    return 0;
}

